-- Auto-resolve BLING (UltraFit) instance ID
DO $$
DECLARE
  v_instance_id UUID;
BEGIN
  SELECT id INTO v_instance_id FROM instances WHERE slug = 'bling' LIMIT 1;
  IF v_instance_id IS NULL THEN
    RAISE EXCEPTION 'Instance BLING/UltraFit not found';
  END IF;
  RAISE NOTICE 'Using instance: %', v_instance_id;

ON CONFLICT (instance_id, phone) DO UPDATE SET
  name = EXCLUDED.name,
  contact_person = EXCLUDED.contact_person,
  email = EXCLUDED.email,
  shipping_street = EXCLUDED.shipping_street,
  shipping_street_line2 = EXCLUDED.shipping_street_line2,
  shipping_postal_code = EXCLUDED.shipping_postal_code,
  shipping_city = EXCLUDED.shipping_city,
  updated_at = now();

END $$;
